import{_ as n,o as i,c as a,ag as t}from"./chunks/framework.gU7RhlGX.js";const c=JSON.parse('{"title":"cli-anything: 让所有软件成为 Agent 原生工具","description":"","frontmatter":{},"headers":[],"relativePath":"工具/cli-anything.md","filePath":"工具/cli-anything.md","lastUpdated":1776422487000}'),e={name:"工具/cli-anything.md"};function l(r,s,g,h,o,p){return i(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="cli-anything-让所有软件成为-agent-原生工具" tabindex="-1">cli-anything: 让所有软件成为 Agent 原生工具 <a class="header-anchor" href="#cli-anything-让所有软件成为-agent-原生工具" aria-label="Permalink to &quot;cli-anything: 让所有软件成为 Agent 原生工具&quot;">​</a></h1><p><strong>CLI-Anything</strong> 是由 <strong>香港大学数据科学实验室 (HKUDS)</strong> 发起的一个开源项目。它的核心目标是：<strong>将任何软件转换为 Agent 原生 (Agent-native) 工具，使其能够被 AI Agent 稳定地控制和操作。</strong></p><p>理解它最直观的一句话：</p><blockquote><p><strong>CLI-Anything 就是：把原本只能“由人点击 GUI 界面”使用的软件，变成 AI 也能通过结构化指令稳定调用的命令行工具。</strong></p></blockquote><hr><h2 id="🚀-为什么需要-cli-anything" tabindex="-1">🚀 为什么需要 CLI-Anything？ <a class="header-anchor" href="#🚀-为什么需要-cli-anything" aria-label="Permalink to &quot;🚀 为什么需要 CLI-Anything？&quot;">​</a></h2><p>目前 AI Agent 在逻辑推理方面表现出色，但在直接操作真实的专业软件（如 GIMP、Blender、LibreOffice）时仍然面临巨大挑战：</p><ul><li><strong>GUI 自动化太脆弱</strong>：页面稍微改变、分辨率波动或弹窗遮挡都会导致操作失败。</li><li><strong>API 覆盖不全</strong>：许多专业软件没有完整的 API，或者 API 文档极其复杂，Agent 难以掌握。</li><li><strong>功能受限的重新实现</strong>：一些简化的替代方案丢失了原软件的专业能力（如滤镜、渲染引擎）。</li></ul><p><strong>CLI-Anything 的路线</strong>：不靠“眼睛”瞎点，而是通过自动化流程为软件套上一层“命令行壳子”，让 AI 像调用工具一样精确调用软件能力。</p><hr><h2 id="🛠️-它如何工作-七阶段自动化流程" tabindex="-1">🛠️ 它如何工作？（七阶段自动化流程） <a class="header-anchor" href="#🛠️-它如何工作-七阶段自动化流程" aria-label="Permalink to &quot;🛠️ 它如何工作？（七阶段自动化流程）&quot;">​</a></h2><p>CLI-Anything 通过以下七步自动化流程，将软件源代码转化为功能完备的 CLI 封装器：</p><ol><li><strong>分析 (Analysis)</strong>：扫描源代码，将原本的 GUI 操作或内部逻辑映射到可调用的接口。</li><li><strong>设计 (Design)</strong>：规划命令的分组（Commands）、状态模型（State Model）和输出格式。</li><li><strong>实现 (Implementation)</strong>：构建基于 Click 的 CLI，支持 <strong>REPL（交互模式）</strong>、<strong>JSON 输出</strong> 以及 <strong>撤销/重做</strong> 功能。</li><li><strong>规格说明与测试规划</strong>：生成 <code>TEST.md</code>，定义详细的单元测试和端到端 (E2E) 测试计划。</li><li><strong>编写测试 (Writing Tests)</strong>：自动实现完整的测试套件。</li><li><strong>文档化 (Documentation)</strong>：更新技术文档，并记录测试执行结果，确保工具可靠。</li><li><strong>发布 (Publishing)</strong>：生成 <code>setup.py</code> 并安装至系统路径，Agent 可直接通过命令发现功能。</li></ol><hr><h2 id="🌟-核心优势-为什么它对-agent-友好" tabindex="-1">🌟 核心优势：为什么它对 Agent 友好？ <a class="header-anchor" href="#🌟-核心优势-为什么它对-agent-友好" aria-label="Permalink to &quot;🌟 核心优势：为什么它对 Agent 友好？&quot;">​</a></h2><ul><li><strong>结构化与可组合</strong>：纯文本命令天然匹配 LLM 的输入格式，可自由串联成复杂工作流。</li><li><strong>自描述性</strong>：Agent 只需运行 <code>--help</code> 就能自动发现所有功能和参数。</li><li><strong>确定性 JSON 输出</strong>：Agent 接收到的不是模糊的屏幕截图，而是结构化的执行结果。</li><li><strong>确定且可靠</strong>：具备撤销/重做和验证机制，Agent 的行为可预测、可纠错。</li><li><strong>轻量通用</strong>：几乎零开销，跨平台运行，不依赖庞大的 GUI 环境。</li></ul><hr><h2 id="💻-典型用法示例" tabindex="-1">💻 典型用法示例 <a class="header-anchor" href="#💻-典型用法示例" aria-label="Permalink to &quot;💻 典型用法示例&quot;">​</a></h2><p>你可以让 CLI-Anything 针对某个 GitHub 仓库或本地源码目录生成工具：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 为 GIMP 生成 CLI 封装</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cli-anything</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> generate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/GNOME/gimp</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>生成的工具（如 <code>cli-anything-gimp</code>）可以如下使用：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># AI 调用的示例指令</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cli-anything-gimp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;photo.jpg&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cli-anything-gimp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> layer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;filter_layer&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cli-anything-gimp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> appliquer-gaussien</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --radius</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cli-anything-gimp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> export</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;output.png&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="🔗-集成与未来" tabindex="-1">🔗 集成与未来 <a class="header-anchor" href="#🔗-集成与未来" aria-label="Permalink to &quot;🔗 集成与未来&quot;">​</a></h2><p>CLI-Anything 致力于构建一个 <strong>Agent 原生软件生态</strong>：</p><ul><li><strong>插件市场</strong>：支持以类似插件的形式托管在 GitHub 上。</li><li><strong>深度集成</strong>：已支持与 <strong>Claude Code</strong>、<strong>OpenClaw</strong>、<strong>Ollama</strong> 等工具集成。</li><li><strong>自主进化</strong>：最终目标是实现 Agent 能够“自主发现新软件 -&gt; 自主构建 CLI -&gt; 分享给其他 Agent”。</li></ul><hr><h2 id="💡-总结" tabindex="-1">💡 总结 <a class="header-anchor" href="#💡-总结" aria-label="Permalink to &quot;💡 总结&quot;">​</a></h2><p>CLI-Anything 正在补齐 AI 基础设施中的关键一环：<strong>让软件从 Human-first (人优先) 进化为 Human + Agent 同等可用。</strong> 它让老牌、深厚的专业软件在 AI 时代焕发新生，成为 Agent 手中真正的武器。</p><hr>`,30)])])}const k=n(e,[["render",l]]);export{c as __pageData,k as default};
